mapper.select:
SELECT * FROM ( SELECT ROWNUM rn, t.* FROM ( SELECT s.surveyId, s.title, s.anonymousYn, s.status, TO_CHAR(s.startDate, 'YYYY-MM-DD') AS startDate, TO_CHAR(s.endDate, 'YYYY-MM-DD') AS endDate, s.writerEmpId, TO_CHAR(s.regDate, 'YYYY-MM-DD') AS regDate, e.name AS writerName, (SELECT COUNT(*) FROM surveyQuestion q WHERE q.surveyId = s.surveyId) AS questionCount, (SELECT COUNT(*) FROM surveyResponse r WHERE r.surveyId = s.surveyId) AS responseCount, (SELECT CASE WHEN COUNT(*)>0 THEN 'Y' ELSE 'N' END FROM surveyResponse WHERE surveyId=s.surveyId AND empId=#{empId}) AS respondedYn FROM survey s LEFT JOIN employee2 e ON s.writerEmpId = e.empId
AND s.title LIKE '%' || #{keyword} || '%'
AND s.status = #{status}
ORDER BY s.regDate DESC ) t WHERE ROWNUM <= #{pageNo} * #{pageSize} ) WHERE rn > (#{pageNo} - 1) * #{pageSize}

SELECT COUNT(*) FROM survey s
AND s.title LIKE '%' || #{keyword} || '%'
AND s.status = #{status}

mapper.update:
UPDATE survey
SET status = #{status}, updateDate = SYSDATE
WHERE surveyId = #{surveyId}

