    SELECT surveyResponse_seq.NEXTVAL FROM dual

INSERT INTO surveyResponse (responseId, surveyId, empId, respondedDate)
SELECT #{responseId}, #{surveyId}, #{empId}, SYSDATE FROM dual
WHERE NOT EXISTS (
    SELECT 1 FROM surveyResponse WHERE surveyId = #{surveyId} AND empId = #{empId}
)

